            <div><label className="block text-sm font-medium mb-1">Model</label><select value={model} onChange={(e) => setModel(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded">{providerDetails.gemini.models.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}</select></div>
            {voices.length > 0 && <div><label className="block text-sm font-medium mb-1">Voice</label><select value={voice} onChange={(e) => setVoice(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded">{voices.map(v => <option key={v.name} value={v.name}>{v.name} ({v.lang})</option>)}</select></div>}
        </form><div className="flex justify-between items-center pt-4 mt-4 border-t border-gray-700 flex-shrink-0"><button type="button" onClick={onBack} className="px-3 py-1 bg-gray-600 rounded text-sm flex items-center"><ArrowLeft size={16} className="mr-1" /> Back</button><div className="space-x-2"><button type="button" onClick={() => setIsPresetOpen(true)} className="px-3 py-1 bg-gray-600 rounded text-sm">Presets</button>{agentToEdit && <button type="button" onClick={() => { setConfirmMessage(`Delete ${agentToEdit.name}?`); setConfirmAction(() => () => { onRemove(agentToEdit.id); onBack(); }); setIsConfirmModalOpen(true);}} className="px-3 py-1 bg-red-500 rounded text-sm">Delete</button>}<button type="button" onClick={handleSubmit} className="px-4 py-2 bg-blue-500 rounded text-white">{agentToEdit ? "Update" : "Create"}</button></div></div>
        <Modal isOpen={isPresetOpen} onClose={() => setIsPresetOpen(false)} title="Character Presets" maxWidth="max-w-sm">{PRESET_CHARACTERS.map((preset, i) => (<button key={i} onClick={() => handlePresetSelect(preset)} className="w-full p-3 bg-gray-700 hover:bg-gray-600 rounded text-left"><div className="font-medium">{preset.name}</div><div className="text-xs text-gray-400 truncate">{preset.prompt}</div></button>))}</Modal>
        </div>
    );
};

