const TimeSinceLastMessage = () => {
    const { messages } = useContext(AppContext);
    const [timeSince, setTimeSince] = useState('');
    useEffect(() => {
        const update = () => {
            if (messages.length === 0 || messages[messages.length - 1].sender === 'system') { setTimeSince(''); return; }
            const lastMessageTime = messages[messages.length - 1].timestamp?.toDate();
            if(!lastMessageTime) return;
            const diff = new Date().getTime() - lastMessageTime.getTime();
            const seconds = Math.floor(diff / 1000);
            if(seconds < 5) setTimeSince('Just now'); else if (seconds < 60) setTimeSince(`${seconds}s ago`); else setTimeSince(`${Math.floor(seconds / 60)}m ago`);
        };
        const interval = setInterval(update, 5000); update(); return () => clearInterval(interval);
    }, [messages]);
    if(!timeSince) return null;
    return <div className="text-xs text-gray-500 dark:text-gray-400 whitespace-nowrap">Last: {timeSince}</div>;
};

const MessageBubble = ({ msg }) => {
