    const isAgentMessage = !isYou && !isSystem;
    const bubbleClass = cn('p-3 rounded-xl max-w-xl relative', isYou && 'bg-blue-600 text-white self-end', isSystem && 'bg-gray-600 text-white text-center italic mx-auto', isAgentMessage && 'bg-gray-700 self-start');
    if (isSystem) return <div className={bubbleClass}><p className="whitespace-pre-wrap">{msg.text}</p></div>;

    return (
        <div className={cn('group flex items-start gap-3 w-full', isYou && 'justify-end')}>
            {!isYou && <img src={agent?.profilePictureUrl || `https://placehold.co/40x40/7c3aed/ffffff?text=${msg.sender.charAt(0)}`} alt={msg.sender} className="w-10 h-10 rounded-full object-cover flex-shrink-0 cursor-pointer" onClick={() => agent?.profilePictureUrl && setImagePreviewUrl(agent.profilePictureUrl)}/>}
            <div className={bubbleClass}>
                {isAgentMessage && (<div className="absolute -top-2 -right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
