    if (!isOpen) return null;
    return (<div className="fixed inset-0 bg-black/75 z-50 flex items-center justify-center p-4" onClick={onClose}><div className={`bg-gray-800 rounded-lg shadow-xl w-full ${maxWidth} max-h-[90vh] flex flex-col`} onClick={e => e.stopPropagation()}><div className="p-4 border-b border-gray-700 flex justify-between items-center sticky top-0 bg-gray-800 z-10 flex-shrink-0"><h3 className="text-lg font-bold flex items-center">{icon && React.cloneElement(icon, { className: "mr-2" })}{title}</h3><button onClick={onClose} className="text-gray-400 hover:text-white"><X size={20} /></button></div><div className="p-4 overflow-y-auto">{children}</div></div></div>);
};

const AgentForm = ({ onSave, onUpdate, onRemove, voices, agentToEdit, onBack, setIsConfirmModalOpen, setConfirmAction, setConfirmMessage }) => {
    const { callImageApi } = useContext(AppContext);
    const [name, setName] = useState('');
    const [systemPrompt, setSystemPrompt] = useState('');
    const [model, setModel] = useState(DEFAULT_MODEL);
    const [voice, setVoice] = useState('');
    const [profilePictureUrl, setProfilePictureUrl] = useState(null);
    const [isGeneratingPic, setIsGeneratingPic] = useState(false);
    const [picError, setPicError] = useState('');
    const [isPresetOpen, setIsPresetOpen] = useState(false);

    useEffect(() => {
        if (agentToEdit) { setName(agentToEdit.name); setSystemPrompt(agentToEdit.systemPrompt); setModel(agentToEdit.model || DEFAULT_MODEL); setVoice(agentToEdit.voice || (voices.length > 0 ? voices[0].name : '')); setProfilePictureUrl(agentToEdit.profilePictureUrl); } 
        else { setName(''); setSystemPrompt(''); setModel(DEFAULT_MODEL); setVoice(voices.length > 0 ? voices[0].name : ''); setProfilePictureUrl(null); }
    }, [agentToEdit, voices]);

    const handleSubmit = (e) => { e.preventDefault(); const agentData = { name, systemPrompt, model, voice, profilePictureUrl, llm: 'gemini' }; if (agentToEdit) onUpdate({ ...agentData, id: agentToEdit.id }); else onSave(agentData); onBack(); };
    const handlePresetSelect = (preset) => { setName(preset.name); setSystemPrompt(preset.prompt); setIsPresetOpen(false); };
    const generatePicture = async () => { if (!systemPrompt.trim()) { setPicError("Please define a system prompt first."); return; } setPicError(''); setIsGeneratingPic(true); try { const picPrompt = `A simple, clean, cartoon-style headshot portrait of: "${systemPrompt}", in a cohesive, digital painting style.`; const imageData = await callImageApi(picPrompt); const resizedImageUrl = await resizeImage(`data:image/png;base64,${imageData}`, 256, 256); setProfilePictureUrl(resizedImageUrl); } catch (error) { setPicError("Couldn't generate picture."); } setIsGeneratingPic(false); };

    return (
        <div className="flex flex-col h-full"><form onSubmit={handleSubmit} className="space-y-4 flex-grow">
            <div><label className="block text-sm font-medium mb-1">Name</label><input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded" required /></div>
            <div><label className="block text-sm font-medium mb-1">System Prompt</label><textarea value={systemPrompt} onChange={(e) => setSystemPrompt(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]" required /></div>
            <div><label className="block text-sm font-medium mb-1">Profile Picture</label><div className="flex items-center gap-4"><img src={profilePictureUrl || 'https://placehold.co/80x80/1f2937/ffffff?text=...'} alt="Profile" className="w-20 h-20 rounded-full object-cover" /><button type="button" onClick={generatePicture} disabled={isGeneratingPic} className="px-4 py-2 bg-indigo-600 text-white rounded-lg disabled:bg-indigo-400">{isGeneratingPic ? 'Generating...' : '✨ Generate'}</button></div>{picError && <p className="text-red-500 text-sm mt-2">{picError}</p>}</div>
            <div><label className="block text-sm font-medium mb-1">Model</label><select value={model} onChange={(e) => setModel(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded">{providerDetails.gemini.models.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}</select></div>
            {voices.length > 0 && <div><label className="block text-sm font-medium mb-1">Voice</label><select value={voice} onChange={(e) => setVoice(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded">{voices.map(v => <option key={v.name} value={v.name}>{v.name} ({v.lang})</option>)}</select></div>}
        </form><div className="flex justify-between items-center pt-4 mt-4 border-t border-gray-700 flex-shrink-0"><button type="button" onClick={onBack} className="px-3 py-1 bg-gray-600 rounded text-sm flex items-center"><ArrowLeft size={16} className="mr-1" /> Back</button><div className="space-x-2"><button type="button" onClick={() => setIsPresetOpen(true)} className="px-3 py-1 bg-gray-600 rounded text-sm">Presets</button>{agentToEdit && <button type="button" onClick={() => { setConfirmMessage(`Delete ${agentToEdit.name}?`); setConfirmAction(() => () => { onRemove(agentToEdit.id); onBack(); }); setIsConfirmModalOpen(true);}} className="px-3 py-1 bg-red-500 rounded text-sm">Delete</button>}<button type="button" onClick={handleSubmit} className="px-4 py-2 bg-blue-500 rounded text-white">{agentToEdit ? "Update" : "Create"}</button></div></div>
        <Modal isOpen={isPresetOpen} onClose={() => setIsPresetOpen(false)} title="Character Presets" maxWidth="max-w-sm">{PRESET_CHARACTERS.map((preset, i) => (<button key={i} onClick={() => handlePresetSelect(preset)} className="w-full p-3 bg-gray-700 hover:bg-gray-600 rounded text-left"><div className="font-medium">{preset.name}</div><div className="text-xs text-gray-400 truncate">{preset.prompt}</div></button>))}</Modal>
        </div>
    );
};

const AgentManagerModal = ({ isOpen, onClose, agents, handleDownloadSetup, handleUploadSetup, ...rest }) => {
    const [view, setView] = useState('list');
    const [currentAgent, setCurrentAgent] = useState(null);
    const fileInputRef = useRef(null);
    const handleEdit = (agent) => { setCurrentAgent(agent); setView('form'); };
    const handleAdd = () => { setCurrentAgent(null); setView('form'); };
    const handleBack = () => { setView('list'); setCurrentAgent(null); };
    useEffect(() => { if (isOpen) setView('list'); }, [isOpen]);
    return (
        <Modal isOpen={isOpen} onClose={onClose} title={view === 'list' ? 'Manage Agents' : (currentAgent ? 'Edit Agent' : 'Create Agent')} icon={<Users />} maxWidth="max-w-2xl">
            {view === 'list' ? (
                <div className="space-y-3">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                        {agents.map(agent => (
                            <div key={agent.id} className="bg-gray-700 p-3 rounded-lg flex items-start space-x-3">
                                <img src={agent.profilePictureUrl || `https://placehold.co/64x64/7c3aed/ffffff?text=${agent.name.charAt(0)}`} alt={agent.name} className="w-16 h-16 rounded-md object-cover flex-shrink-0" />
                                <div className="flex-grow">
                                    <h4 className="font-bold">{agent.name}</h4>
                                    <p className="text-xs text-gray-400 italic line-clamp-2">{agent.systemPrompt}</p>
                                    <button onClick={() => handleEdit(agent)} className="mt-2 text-xs px-2 py-1 bg-blue-600 rounded">Edit</button>
                                </div>
                            </div>
                        ))}
                    </div>
                    {agents.length === 0 && <p className="text-gray-500 text-center py-8">No agents created yet.</p>}
                    <div className="pt-4 flex justify-between items-center">
                        <div className="flex gap-2">
                             <button onClick={handleDownloadSetup} className="px-3 py-2 bg-gray-600 text-white rounded-lg text-sm flex items-center gap-2"><Download size={16}/> Download Setup</button>
                             <input type="file" ref={fileInputRef} onChange={handleUploadSetup} className="hidden" accept=".json"/>
                             <button onClick={() => fileInputRef.current.click()} className="px-3 py-2 bg-gray-600 text-white rounded-lg text-sm flex items-center gap-2"><Upload size={16}/> Upload Setup</button>
                        </div>
                        <button onClick={handleAdd} className="px-4 py-2 bg-green-600 rounded-lg"><Plus className="inline mr-2" size={16}/>Add New Agent</button>
                    </div>
                </div>
            ) : ( <AgentForm agentToEdit={currentAgent} onBack={handleBack} {...rest} /> )}
        </Modal>
    );
};

const GoalModal = ({ isOpen, onClose, onSet, initialGoal }) => {
    const [goal, setGoal] = useState(initialGoal || '');
    useEffect(() => { setGoal(initialGoal || ''); }, [initialGoal]);
    const handleSubmit = (e) => { e.preventDefault(); onSet(goal); onClose(); };
    return (<Modal isOpen={isOpen} onClose={onClose} title="Set Conversation Goal" icon={<Lightbulb />}><form onSubmit={handleSubmit} className="space-y-4"><textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]" placeholder="Example: 'Plan a heist to steal the Mona Lisa'"/><div className="flex justify-end"><button type="submit" className="px-4 py-2 bg-blue-500 rounded text-white">Set Goal</button></div></form></Modal>);
};

const RuleModal = ({ isOpen, onClose, rules, agents }) => {
    const getAgentName = (id) => agents.find(a => a.id === id)?.name || 'Unknown';
    return (<Modal isOpen={isOpen} onClose={onClose} title="Active Conversation Rules" icon={<Copy />}><div className="space-y-4"><p className="text-gray-400">These are the active rules driving the conversation in 'auto' mode, generated by AI based on the scenario goal and agent personas.</p>{rules.length > 0 ? (<div className="bg-gray-900 p-3 rounded space-y-2">{rules.map((rule, i) => (<div key={i} className="flex items-center space-x-2 text-sm"><span>{getAgentName(rule.sourceId)}</span><span className="text-blue-400">→</span><span>{getAgentName(rule.targetId)}</span></div>))}</div>) : (<p className="text-center text-gray-500 py-4">No rules generated yet. Use the 'Automate' feature to create a scenario.</p>)}</div></Modal>);
};

const TopicModal = ({ isOpen, onClose, onInject, onSuggest }) => {
    const [topic, setTopic] = useState('');
    const [isSuggesting, setIsSuggesting] = useState(false);
    const handleSubmit = (e) => { e.preventDefault(); if(topic.trim()){ onInject(topic); setTopic(''); onClose(); } };
    const handleSuggest = async () => { setIsSuggesting(true); const suggestion = await onSuggest(); setTopic(suggestion); setIsSuggesting(false); };
    return (<Modal isOpen={isOpen} onClose={onClose} title="Inject New Topic" icon={<Zap />}><form onSubmit={handleSubmit} className="space-y-4"><textarea value={topic} onChange={(e) => setTopic(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]" placeholder="Example: 'Suddenly, the power goes out...'"/><div className="flex justify-between"><button type="button" onClick={handleSuggest} className="px-4 py-2 bg-purple-600 text-white rounded-lg flex items-center" disabled={isSuggesting}><Sparkles size={16} className="mr-2"/> {isSuggesting ? "Suggesting..." : "Suggest Topic"}</button><button type="submit" className="px-4 py-2 bg-blue-500 rounded text-white">Inject Topic</button></div></form></Modal>);
};

const ClearModal = ({ isOpen, onClose, onClearMessages, onClearAll }) => (<Modal isOpen={isOpen} onClose={onClose} title="Clear Scenario" icon={<Eraser />}><div className="space-y-4 text-center"><p className="text-gray-300">Choose what you would like to clear.</p><div className="flex justify-center space-x-4 pt-2"><button onClick={() => {onClearMessages(); onClose();}} className="px-4 py-2 bg-yellow-600 text-white rounded-lg">Clear Messages Only</button><button onClick={() => {onClearAll(); onClose();}} className="px-4 py-2 bg-red-500 text-white rounded-lg">Clear Entire Scenario</button></div></div></Modal>);

const EditMessageModal = ({ isOpen, onClose, onSave, message }) => {
    if (!isOpen || !message) return null;
    const [text, setText] = useState(message.text);
    return (<Modal isOpen={isOpen} onClose={onClose} title="Edit & Regenerate" icon={<Edit />}><div className="space-y-4"><textarea value={text} onChange={(e) => setText(e.target.value)} rows="6" className="w-full p-2 bg-gray-700 border border-gray-600 rounded" /><div className="flex justify-end gap-3"><button onClick={onClose} className="px-4 py-2 bg-gray-600 rounded-lg">Cancel</button><button onClick={() => onSave(text)} className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600">Save & Regenerate</button></div></div></Modal>);
};

const TimeSinceLastMessage = () => {
    const { messages } = useContext(AppContext);
    const [timeSince, setTimeSince] = useState('');
    useEffect(() => { const update = () => { if (messages.length === 0 || messages[messages.length - 1].sender === 'system') { setTimeSince(''); return; } const lastMessageTime = messages[messages.length - 1].timestamp?.toDate(); if(!lastMessageTime) return; const diff = new Date().getTime() - lastMessageTime.getTime(); const seconds = Math.floor(diff / 1000); if(seconds < 5) setTimeSince('Just now'); else if (seconds < 60) setTimeSince(`${seconds}s ago`); else setTimeSince(`${Math.floor(seconds / 60)}m ago`); }; const interval = setInterval(update, 5000); update(); return () => clearInterval(interval); }, [messages]);
    if(!timeSince) return null;
    return <div className="text-xs text-gray-500 dark:text-gray-400 whitespace-nowrap">Last: {timeSince}</div>;
};

const MessageBubble = ({ msg }) => {
    const { getAgentById, setImagePreviewUrl, handleStartEdit, confirmRegeneration } = useContext(AppContext);
    const agent = msg.agentId ? getAgentById(msg.agentId) : null;
    const isYou = msg.sender === 'You';
    const isSystem = msg.sender === 'system';
    const isAgentMessage = !isYou && !isSystem;
    const bubbleClass = cn('p-3 rounded-xl max-w-xl relative', isYou && 'bg-blue-600 text-white self-end', isSystem && 'bg-gray-600 text-white text-center italic mx-auto', isAgentMessage && 'bg-gray-700 self-start');
    if (isSystem) return <div className={bubbleClass}><p className="whitespace-pre-wrap">{msg.text}</p></div>;

    return (
        <div className={cn('group flex items-start gap-3 w-full', isYou && 'justify-end')}>
            {!isYou && <img src={agent?.profilePictureUrl || `https://placehold.co/40x40/7c3aed/ffffff?text=${msg.sender.charAt(0)}`} alt={msg.sender} className="w-10 h-10 rounded-full object-cover flex-shrink-0 cursor-pointer" onClick={() => agent?.profilePictureUrl && setImagePreviewUrl(agent.profilePictureUrl)}/>}
            <div className={bubbleClass}>
                {isAgentMessage && (<div className="absolute -top-2 -right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => handleStartEdit(msg)} className="p-1 rounded-full text-white bg-black/30 hover:bg-black/50"><Edit size={12} /></button>
                        <button onClick={() => confirmRegeneration(msg)} className="p-1 rounded-full text-white bg-black/30 hover:bg-black/50"><RefreshCw size={12} /></button>
                </div>)}
                {!isYou && <div className="font-semibold text-sm mb-1">{msg.sender}</div>}
                <p className="whitespace-pre-wrap break-words">{msg.text}</p>
            </div>
        </div>
    );
};

const TypingIndicator = () => (<div className="flex items-center space-x-1 p-4 self-start"><div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div><div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div><div className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></div></div>);

const ConfirmationModal = ({ isOpen, onClose, onConfirm, message }) => { if(!isOpen) return null; return <Modal isOpen={isOpen} onClose={onClose} title="Confirm Action" icon={<Trash2 />} maxWidth="max-w-sm"><div className="space-y-4"><p className="text-gray-300">{message}</p><div className="flex justify-end space-x-3"><button onClick={onClose} className="px-4 py-2 bg-gray-600 rounded-lg">Cancel</button><button onClick={onConfirm} className="px-4 py-2 bg-red-500 text-white rounded-lg">Confirm</button></div></div></Modal> };

const ImagePreviewModal = ({ imageUrl, onClose }) => { if (!imageUrl) return null; return <div className="fixed inset-0 bg-black/90 z-50 flex items-center justify-center p-4 cursor-pointer" onClick={onClose}><div className="max-w-[90vw] max-h-[90vh]"><img src={imageUrl} alt="Preview" className="max-w-full max-h-full object-contain" onClick={e => e.stopPropagation()}/></div></div> };

const SynthesisJobCard = ({ job, callImageApi, addGeneratedClipToBin }) => {
    const [generatingImages, setGeneratingImages] = useState([]);
    const generateImage = async (prompt, index) => { setGeneratingImages(prev => [...prev, index]); try { const imageData = await callImageApi(prompt); await addGeneratedClipToBin(prompt, imageData); } catch (error) { console.error("Image generation failed:", error); } finally { setGeneratingImages(prev => prev.filter(i => i !== index)); } };
    return ( <div className="bg-gray-800 rounded-lg p-4 mb-4"><h3 className="font-bold text-lg mb-2">Synthesis - {new Date(job.timestamp?.toDate()).toLocaleString()}</h3><div className="mb-4"><h4 className="font-semibold">Summary:</h4><p className="text-sm text-gray-400 italic">"{job.summary}"</p></div><div><h4 className="font-semibold">Generated Scenes:</h4><div className="space-y-2 mt-2">{job.imagePrompts?.map((prompt, i) => (<div key={i} className="bg-gray-900 p-3 rounded-lg flex items-center justify-between"><p className="text-sm font-mono flex-1">"{prompt}"</p><button onClick={() => generateImage(prompt, i)} className="ml-4 px-3 py-1 bg-blue-500 rounded-lg text-sm" disabled={generatingImages.includes(i)}>{generatingImages.includes(i) ? "Generating..." : "Generate & Add"}</button></div>))}</div></div></div> );
};

const SynthesisGalleryModal = ({ isOpen, onClose }) => {
    const { synthesisJobs, callImageApi, addGeneratedClipToBin } = useContext(AppContext);
    return (<Modal isOpen={isOpen} onClose={onClose} title="Media Synthesis Gallery" icon={<GalleryHorizontal />} maxWidth="max-w-4xl"><div className="overflow-y-auto h-full">{synthesisJobs.length > 0 ? ([...synthesisJobs].reverse().map(job => (<SynthesisJobCard key={job.id} job={job} callImageApi={callImageApi} addGeneratedClipToBin={addGeneratedClipToBin}/>))) : (<p className="text-center text-gray-500 py-8">No media synthesized yet.</p>)}</div></Modal>);
};

const VideoEditorInterface = () => {
    const { videoClips, audioClips, timelineVideo, timelineAudio, isPlaying, currentTime, setIsPlaying, setCurrentTime, previewSource, setPreviewSource, isDescriptionModalOpen, setIsDescriptionModalOpen, isGeneratingDescription, setIsGeneratingDescription, generatedDescription, setGeneratedDescription, descriptionError, setDescriptionError, isTitleModalOpen, setIsTitleModalOpen, isGeneratingTitle, setIsGeneratingTitle, generatedTitles, setGeneratedTitles, titleError, setTitleError, isAiClipModalOpen, setIsAiClipModalOpen, isAiStoryboardModalOpen, setIsAiStoryboardModalOpen, handleFileUpload, handleMetadata, addToTimeline, removeFromTimeline, addGeneratedClipToBin, callTextApi, callImageApi, setImagePreviewUrl } = useContext(AppContext);
