            <footer className="bg-gray-800 shadow-inner p-4">
                <div className="flex items-center gap-2 mb-3"><label className="text-sm">From:</label><select value={senderId} onChange={e => setSenderId(e.target.value)} className="w-full p-2 border rounded-lg bg-gray-700 border-gray-600 text-sm"><option value="You">You</option>{agents.map(a => (<option key={a.id} value={a.id}>{a.name}</option>))}</select><label className="text-sm">To:</label><select value={recipientAgentId} onChange={e => setRecipientAgentId(e.target.value)} disabled={mode === 'auto'} className="w-full p-2 border rounded-lg bg-gray-700 border-gray-600"><option value="">All</option>{agents.map(a => (<option key={a.id} value={a.id}>{a.name}</option>))}</select></div>
                {suggestions.length > 0 && <div className="flex flex-wrap gap-2 mb-2">{suggestions.map((s, i) => (<button key={i} onClick={() => { setInputValue(s); setSuggestions([]); }} className="px-3 py-1 bg-gray-700 rounded-full text-sm hover:bg-gray-600">{s}</button>))}</div>}
                <div className="flex items-center space-x-2">
                    <div className="flex-1 relative">
                        <input type="text" ref={inputRef} value={inputValue} onChange={e => setInputValue(e.target.value)} onKeyDown={handleKeyDown} placeholder={isGenerating ? "Thinking..." : "Type a message..."} disabled={isGenerating || agents.length === 0} className="w-full p-2 pr-20 bg-transparent border border-gray-600 rounded-full"/>
                        <button onClick={handleSuggest} disabled={isSuggesting} className="absolute right-10 top-1/2 -translate-y-1/2 px-3 py-1 text-sm bg-blue-800 text-blue-200 rounded-full hover:bg-blue-700 disabled:opacity-50">✨ Suggest</button>
