                    <button onClick={handleSendMessage} className="p-3 bg-blue-500 text-white rounded-full disabled:bg-gray-400" disabled={!inputValue.trim() || isGenerating || agents.length === 0}><svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 12h14M12 5l7 7-7 7"/></svg></button>
                </div>
            </footer>
            <AgentManagerModal isOpen={isAgentModalOpen} onClose={() => setIsAgentModalOpen(false)} onSave={handleAddAgent} onUpdate={handleUpdateAgent} onRemove={handleRemoveAgent} voices={voices} agents={agents} setIsConfirmModalOpen={setIsConfirmModalOpen} setConfirmAction={setConfirmAction} setConfirmMessage={setConfirmMessage} handleDownloadSetup={handleDownloadSetup} handleUploadSetup={handleUploadSetup} />
            <GoalModal isOpen={isGoalModalOpen} onClose={() => setIsGoalModalOpen(false)} onSet={handleSetConversationGoal} initialGoal={conversationGoal}/>
            <RuleModal isOpen={isRuleModalOpen} onClose={() => setIsRuleModalOpen(false)} rules={rules} agents={agents}/>
            <SynthesisGalleryModal isOpen={isGalleryOpen} onClose={() => setIsGalleryOpen(false)}/>
            <TopicModal isOpen={isTopicModalOpen} onClose={() => setIsTopicModalOpen(false)} onInject={handleInjectTopic} onSuggest={handleSuggestTopic}/>
            <ClearModal isOpen={isClearModalOpen} onClose={() => setIsClearModalOpen(false)} onClearMessages={handleClearMessages} onClearAll={handleClearAll}/>
            <ConfirmationModal isOpen={isConfirmModalOpen} onClose={() => setIsConfirmModalOpen(false)} onConfirm={() => { if (confirmAction) confirmAction(); setIsConfirmModalOpen(false);}} message={confirmMessage}/>
            <EditMessageModal isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} message={messageToEdit} onSave={handleUpdateMessageAndRegenerate} />
            <ImagePreviewModal imageUrl={imagePreviewUrl} onClose={() => setImagePreviewUrl(null)} />
        </div>
    );
};

